async (params, browser) => {
  // Open Todoist
  await browser.open('https://app.todoist.com/app/upcoming')

  // Wait for page
  await browser.waitForSelector('.task_list, [class*="task"], .content', 15000)

  // Let page render
  await browser.wait(2500)

  // Extract data
  const result = await browser.evaluate(`const tasks = []; document.querySelectorAll('.task_list_item, [class*="task_item"]').forEach((el, i) => { if (i < 30) { const nameEl = el.querySelector('.task_content, [class*="content"]'); const dueEl = el.querySelector('.due_date, time'); tasks.push({ name: nameEl?.textContent?.trim() || '', due: dueEl?.textContent?.trim() || '' }); } }); return { task_count: tasks.length, tasks };`)

  return result
}
